INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-6f0ba476-moex-00461', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於買賣契約危險負擔之敘述，何者正確？', '["試驗買賣不適用民法第373 條危險負擔之規定", "買賣標的物之利益及危險，自交付時起，均由買受人承受負擔，惟 買賣標的物之權利尚未移轉者，不在此限", "甲將自己所有的 A 屋出賣於乙，過戶後交屋前，A 屋遭無名火焚 毀，因甲、乙約定危險負擔自過戶時起便移轉予乙，甲要求乙仍應 支付買賣價金。惟因甲尚未交付 A屋，故乙無須支付價金", "甲將A冰箱出賣於乙，約定送到新北市住家。後來乙與甲合意變更 清償地為基隆市。甲遂將A 冰箱交付給貨運行丙運送，運送途中發 生大地震，A 冰箱被巨石砸毀。依民法規定，乙無須支付價金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00462', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '開餐廳之甲僱用乙為店員，下列關於僱傭契約之敘述，何者錯誤？', '["甲、乙間之僱傭契約定有期限，除非契約期限屆滿，否則不得終止 契約", "甲、乙得約定每個月初先領薪水", "若乙於應徵時，表示曾赴法國藍帶餐飲學校學習廚藝並取得證照， 擅長法式料理，因而錄取。實則沒有去過法國也不會做法國料理， 甲得終止契約", "若乙在端送料理時，遭酒醉客人打傷，得向甲請求賠償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00463', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲贈與乙1 台超跑，並要求乙須在5 年內每月到療養院當義工4 個小 時，乙表示同意。下列敘述，何者正確？', '["贈與人甲若已為給付，縱使受贈人乙因開刀住院而一時未能履行負 擔，療養院得逕予撤銷贈與", "附負擔之給付，若高於贈與物之價格者，超過之部分，受贈人無履 行責任", "贈與人不負擔物之瑕疵擔保責任", "甲、乙間之契約，為雙務契約，甲請求乙到療養院當義工，即為其 對價"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00464', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲、乙、丙、丁共同繼承A 地，尚未辦畢繼承登記，甲、乙、丙、丁 與戊訂立買賣契約，將 A地賣給戊。買賣契約之效力為何？', '["有效", "無效", "得撤銷", "效力未定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00465', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲出賣 A屋於乙，雖已交付，但未辦理所有權移轉登記。其後甲將該 屋出賣於丙，並辦理所有權移轉登記。有關丙行使物上請求權，下列 敘述，何者正確？', '["丙不得向乙主張物上請求權，因乙基於與甲之買賣契約，乃有權占有", "丙不得向乙主張物上請求權，僅得對甲主張債務不履行之損害賠償", "丙得向乙主張物上請求權，惟乙亦得以其與甲之買賣契約抗辯而拒絕 返還", "丙得向乙主張物上請求權而請求乙返還，乙僅得對甲主張債務不履行 之損害賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00466', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者應以共有人過半數及其應有部分合計過半數，或其應有部分 合計逾三分之二之同意，始得為之？', '["共有不動產之應有部分上設定普通抵押權之行為", "共有動產設定質權之行為", "共有不動產之管理決定", "共有不動產之分割協議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00467', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者非屬民法所規定，普通抵押權人於實行抵押權時，得主張併 付拍賣標的物之情形？', '["土地所有人於設定抵押權後，有必要時可在抵押之土地上營造建築物", "以建築物設定抵押權，其抵押物存在所必要之權利得讓與者", "以建築物為抵押者，於抵押權設定後所附加於該建築物而具獨立性之 附加部分", "抵押物之成分非依物之通常用法而分離成為獨立之動產者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00468', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於法人成立之敘述，何者錯誤？', '["財團法人與社團法人均應經中央主管機關之同意，始得設立登記", "營利社團法人之登記，依特別法規定", "財團法人之登記主管機關，為該法人事務所所在地之法院", "受設立許可之法人，其主管機關得檢查其財產狀況"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00469', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '乙受甲之概括委任，為其處理事務。下列敘述，何者正確？', '["委任契約屬不要式、有償契約", "乙若未受甲之特別委任，則不得為甲為受贈之行為", "甲有房屋想出租，乙得自行作主，與欲承租該房屋之承租人訂立 1 年之房屋租賃契約", "若約定甲應給付乙報酬，故乙在處理甲之事務時，應負與處理自己 事務同一之注意義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00470', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲男為完全行為能力人，甲男之結婚於下列何種情形為無效？', '["甲男與雖有意思能力但受監護宣告之乙女結婚", "甲男與媳婦之寡母丙結婚", "甲男與離婚之大嫂丁結婚", "甲男與喪偶之媳婦戊結婚"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
